  ('rota95_config_site', '{"nomeLoja":"ROTA 95 Motopeças e Oficina","slogan":"Peças de qualidade. Atendimento de verdade.","email":"motopecas.rota95@gmail.com","telefoneAlternativo":"","cidade":"Camboriú/SC","endereco":"R. Jailson Francisco de Miranda","horario":"Seg. à Sex. 8h às 18h","parcelasMax":12,"jurosParcelamento":0,"pixDesconto":4.99,"chavePix":"","taxaEntrega":50,"freteGratisAcima":150,"historiaTitulo":"ROTA 95 Motopeças e Oficina","historiaTexto":"A ROTA 95 nasceu de um sonho compartilhado entre pai e filho, unidos pela paixão por motos, pelo estilo country e pela vontade de construir algo diferente. Antes mesmo da oficina física abrir as portas, começamos vendendo motopeças, conquistando a confiança de cada cliente e transformando ideias simples em um projeto cheio de propósito.\n\nMais do que uma loja ou oficina, queremos criar um espaço onde tradição e novas ideias caminhem juntas. Um lugar com alma de estrada, atendimento verdadeiro e compromisso em oferecer sempre o melhor para quem confia na ROTA 95.","compraTitulo":"Compre pelo site ou WhatsApp","compraTexto":"Escolha os produtos, adicione ao carrinho e finalize a compra pelo site ou WhatsApp. Depois, selecione a forma de pagamento e combine a retirada ou entrega.","jornadaTitulo":"A ROTA 95 está chegando!","jornadaTexto":"Em breve teremos uma oficina completa para cuidar da sua moto com o mesmo compromisso, qualidade e atendimento de verdade que você já encontra nas nossas peças.","jornadaCidade":"Em breve em Camboriú/SC","reviewTitulo1":"Atendimento rápido","reviewTexto1":"“Tirei dúvida pelo WhatsApp e fui bem atendido.”","reviewEstrelas1":5,"reviewTitulo2":"Visual de confiança","reviewTexto2":"“A marca passa seriedade, diferente das lojas comuns.”","reviewEstrelas2":5,"reviewTitulo3":"Peças para o dia a dia","reviewTexto3":"“Ótimo para comprar itens de manutenção da moto.”","reviewEstrelas3":5}', now()),
